using Microsoft.AspNetCore.HttpOverrides;
using Microsoft.Extensions.Http;

var builder = WebApplication.CreateBuilder(args);

// [Breaking Change 4] ValidateScopes is now enabled in Development by default.
// A singleton capturing a scoped service throws InvalidOperationException on startup.
// Fix: register CacheService as scoped so the lifetime matches IUserService.
builder.Services.AddScoped<IUserService, UserService>();
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));

// [Breaking Change 2] HttpClientFactory now uses SocketsHttpHandler by default.
// Casting PrimaryHandler to HttpClientHandler throws InvalidCastException.
// Fix: use ConfigurePrimaryHttpMessageHandler to set the handler type explicitly.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() => new SocketsHttpHandler { UseCookies = false });

// [Breaking Change 3] Trace-level header logging is now redacted by default.
// Fix: explicitly allowlist non-sensitive headers you need for debugging.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(h =>
        !string.Equals(h, "X-Request-Id", StringComparison.OrdinalIgnoreCase) &&
        !string.Equals(h, "X-Correlation-Id", StringComparison.OrdinalIgnoreCase)));

// [Breaking Change 5] ForwardedHeadersMiddleware now ignores X-Forwarded-* headers
// from proxies that are not in KnownProxies or KnownNetworks.
// Fix: register your trusted reverse-proxy addresses.
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    options.KnownProxies.Add(System.Net.IPAddress.Parse("127.0.0.1"));
});

var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

